class SeatManager {
public:
    SeatManager(int n) {
        for (int i = 1; i <= n; i++) {
            available_seats.push(i);
        }
    }

    int reserve() {
        int seat = available_seats.top();
        available_seats.pop();
        return seat;
    }

    void unreserve(int seatNumber) {
        available_seats.push(seatNumber);
    }

private:
    std::priority_queue<int, std::vector<int>, std::greater<int>> available_seats;
};
```
